#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;
use File::Basename;

sub extract_info {
    my ($file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($file);

    # Get the first page
    my $page = $pdf->open_page(1);

    # Get the text from the page
    my $content = $page->text;

    # Convert the content to a list of lines
    my @lines = split /\n/, $content;

    my $author = undef;
    my $title = undef;
    my $date = undef;

    foreach my $line (@lines) {
        if ($line =~ /Author:\s*(.*)/) {
            $author = $1;
        }
        elsif ($line =~ /Title:\s*(.*)/) {
            $title = $1;
        }
        elsif ($line =~ /CreationDate:\s*(.*)/) {
            $date = $1;
        }
    }

    return { author => $author, title => $title, date => $date };
}

